<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ToolError</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">SystemError</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">msg</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#89B4FA;font-style:italic;"> write!</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">f</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;System error: </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> msg</span><span style="color:#9399B2;">),</span></span>
