<span class="line"><span style="color:#CBA6F7;">impl</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">error</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Error</span><span style="color:#CBA6F7;"> for</span><span style="color:#F9E2AF;font-style:italic;"> ToolError</span><span style="color:#9399B2;"> {}</span></span>
